import { Outlet, Navigate, useLocation } from 'react-router-dom';
import { Sidebar } from './Sidebar';
import { useAuth } from '@/contexts/AuthContext';
import { Loader2 } from 'lucide-react';
import AIChatPanel from '@/components/AIChatPanel';

interface AppLayoutProps {
    requireAuth?: boolean;
}

export function AppLayout({ requireAuth = true }: AppLayoutProps) {
    const { user, loading } = useAuth();

    // Show loading spinner while checking auth
    if (loading) {
        return (
            <div className="h-screen w-screen flex items-center justify-center bg-ch-black">
                <div className="flex flex-col items-center gap-3">
                    <Loader2 className="w-8 h-8 text-ch-orange animate-spin" />
                    <div className="flex flex-col items-center">
                        <span className="text-ch-white font-medium">Click.Hero</span>
                        <span className="text-ch-text-muted text-xs">Sincronizando seu ecossistema...</span>
                    </div>
                </div>
            </div>
        );
    }

    // Redirect to login if not authenticated and auth is required
    // Only redirect if loading is finished AND we explicitly have no user
    if (requireAuth && !user) {
        console.log('[AppLayout] No user found, redirecting to login');
        return <Navigate to="/login" replace />;
    }

    return (
        <div className="flex h-screen overflow-hidden bg-ch-black">
            <Sidebar />
            <main className="flex-1 overflow-y-auto">
                <div className="animate-fade-in">
                    <Outlet />
                </div>
            </main>
            <AIChatPanel />
        </div>
    );
}

// Auth layout for login/register pages
export function AuthLayout() {
    const { user, loading } = useAuth();

    // Show loading spinner while checking auth
    if (loading) {
        return (
            <div className="h-screen w-screen flex items-center justify-center bg-ch-black">
                <div className="flex flex-col items-center gap-3">
                    <Loader2 className="w-8 h-8 text-ch-orange animate-spin" />
                    <span className="text-ch-text-muted text-sm">Carregando...</span>
                </div>
            </div>
        );
    }

    const location = useLocation();
    const isLogin = location.pathname === '/login';

    if (user) {
        return <Navigate to="/dashboard" replace />;
    }

    if (isLogin) {
        return <Outlet />;
    }

    return (
        <div className="min-h-screen flex items-center justify-center bg-ch-black p-4">
            <div className="w-full max-w-md animate-fade-in">
                <Outlet />
            </div>
        </div>
    );
}

import { NavLink, useLocation } from 'react-router-dom';
import {
    LayoutDashboard,
    Megaphone,
    Palette,
    FileCheck,
    ClipboardList,
    Settings,
    Users,
    Building2,
    LogOut,
    ChevronLeft,
    ChevronRight,
    BarChart,
    Briefcase,
    CreditCard,
    Search
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { useAuth, useIsSuperAdmin, useIsCompanyAdmin } from '@/contexts/AuthContext';
import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import logo1 from '@/assets/login/logo-1.jpeg';

interface NavItem {
    icon: React.ElementType;
    label: string;
    href: string;
    roles?: Array<'super_admin' | 'company_admin' | 'operador'>;
}

const mainNavItems: NavItem[] = [
    { icon: LayoutDashboard, label: 'Dashboard', href: '/dashboard' },
    // { icon: Search, label: 'Google Ads', href: '/google-ads' },
    { icon: Megaphone, label: 'Campanhas', href: '/campanhas' },
    { icon: Palette, label: 'Criativos', href: '/criativos' },
    { icon: FileCheck, label: 'Auditorias', href: '/auditorias' },
    { icon: ClipboardList, label: 'Políticas', href: '/politicas' },
    { icon: BarChart, label: 'Relatórios', href: '/relatorios' },
    { icon: Briefcase, label: 'Marca', href: '/brand' },
];

const settingsNavItems: NavItem[] = [
    { icon: Settings, label: 'Integrações', href: '/integracoes', roles: ['super_admin', 'company_admin'] },
    { icon: Users, label: 'Usuários', href: '/usuarios', roles: ['super_admin', 'company_admin'] },
    { icon: Building2, label: 'Empresa', href: '/empresa', roles: ['super_admin', 'company_admin'] },
    { icon: CreditCard, label: 'Cobrança', href: '/billing', roles: ['super_admin', 'company_admin'] },
];

export function Sidebar() {
    const location = useLocation();
    const { user, signOut } = useAuth();
    const isSuperAdmin = useIsSuperAdmin();
    const isCompanyAdmin = useIsCompanyAdmin();
    const [collapsed, setCollapsed] = useState(false);

    const filterByRole = (items: NavItem[]) => {
        return items.filter(item => {
            if (!item.roles) return true;
            if (!user?.role) return false;
            return item.roles.includes(user.role);
        });
    };

    const isActive = (href: string) => location.pathname === href;

    return (
        <aside
            className={cn(
                'h-screen bg-[#0c0d0a]/80 backdrop-blur-xl border-r border-white/5 flex flex-col transition-all duration-500 ease-in-out relative',
                collapsed ? 'w-20' : 'w-64'
            )}
        >
            {/* Logo */}
            <div className="h-20 flex items-center px-5 border-b border-white/5 overflow-hidden">
                <motion.div
                    layout
                    className="flex items-center gap-3"
                >
                    <div className="w-10 h-10 bg-gradient-to-br from-ch-orange to-[#e07d04] rounded-xl flex items-center justify-center shadow-lg shadow-ch-orange/20 flex-shrink-0 overflow-hidden">
                        <img src={logo1} alt="ClickHero" className="w-full h-full object-cover" />
                    </div>
                    {!collapsed && (
                        <motion.div
                            initial={{ opacity: 0, x: -10 }}
                            animate={{ opacity: 1, x: 0 }}
                            className="flex flex-col"
                        >
                            <span className="font-bold text-lg leading-tight tracking-tight text-ch-white">
                                Click<span className="text-ch-orange">.</span>Hero
                            </span>
                            <span className="text-[10px] uppercase tracking-[0.2em] text-ch-text-dimmed font-medium">
                                Inteligência Publicitária
                            </span>
                        </motion.div>
                    )}
                </motion.div>
            </div>

            {/* Collapse Toggle */}
            <button
                onClick={() => setCollapsed(!collapsed)}
                className="absolute -right-3 top-24 w-7 h-7 bg-ch-dark-gray border border-white/10 rounded-full flex items-center justify-center hover:bg-ch-orange hover:border-ch-orange text-ch-text-muted hover:text-ch-black transition-all duration-300 z-50 shadow-xl"
            >
                {collapsed ? (
                    <ChevronRight className="w-4 h-4" />
                ) : (
                    <ChevronLeft className="w-4 h-4" />
                )}
            </button>

            {/* Main Navigation */}
            <nav className="flex-1 py-6 px-3 overflow-y-auto scrollbar-thin">
                <div className="space-y-1.5">
                    {mainNavItems.map((item, idx) => (
                        <motion.div
                            key={item.href}
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            transition={{ delay: idx * 0.05 }}
                        >
                            <NavLink
                                to={item.href}
                                className={cn(
                                    'flex items-center gap-3 px-3 py-3 rounded-xl text-sm font-medium transition-all duration-300 group relative',
                                    isActive(item.href)
                                        ? 'bg-ch-orange/10 text-ch-orange shadow-inner shadow-ch-orange/5'
                                        : 'text-ch-text-muted hover:bg-white/5 hover:text-ch-white'
                                )}
                            >
                                {isActive(item.href) && (
                                    <motion.div
                                        layoutId="active-pill"
                                        className="absolute left-0 w-1 h-6 bg-ch-orange rounded-r-full"
                                    />
                                )}
                                <item.icon className={cn(
                                    "w-5 h-5 flex-shrink-0 transition-transform duration-300",
                                    isActive(item.href) ? "scale-110" : "group-hover:scale-110"
                                )} />
                                {!collapsed && (
                                    <span className="truncate">{item.label}</span>
                                )}
                            </NavLink>
                        </motion.div>
                    ))}
                </div>

                {/* Settings Section */}
                {(isCompanyAdmin || isSuperAdmin) && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        transition={{ delay: 0.4 }}
                    >
                        <div className="mt-8 mb-3 px-4">
                            {!collapsed ? (
                                <span className="text-[10px] font-bold uppercase tracking-wide text-ch-text-dimmed/60">
                                    Configurações
                                </span>
                            ) : (
                                <span className="text-[10px] font-black uppercase tracking-wide text-ch-text-muted mb-4 px-2 block">
                                    Configurações
                                </span>
                            )}
                        </div>
                        <div className="space-y-1.5">
                            {filterByRole(settingsNavItems).map((item, idx) => (
                                <motion.div
                                    key={item.href}
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: 0.5 + idx * 0.05 }}
                                >
                                    <NavLink
                                        to={item.href}
                                        className={cn(
                                            'flex items-center gap-3 px-3 py-3 rounded-xl text-sm font-medium transition-all duration-300 group relative',
                                            isActive(item.href)
                                                ? 'bg-ch-orange/10 text-ch-orange shadow-inner shadow-ch-orange/5'
                                                : 'text-ch-text-muted hover:bg-white/5 hover:text-ch-white'
                                        )}
                                    >
                                        {isActive(item.href) && (
                                            <motion.div
                                                layoutId="active-pill-settings"
                                                className="absolute left-0 w-1 h-6 bg-ch-orange rounded-r-full"
                                            />
                                        )}
                                        <item.icon className={cn(
                                            "w-5 h-5 flex-shrink-0 transition-transform duration-300",
                                            isActive(item.href) ? "scale-110" : "group-hover:scale-110"
                                        )} />
                                        {!collapsed && (
                                            <span className="truncate">{item.label}</span>
                                        )}
                                    </NavLink>
                                </motion.div>
                            ))}
                        </div>
                    </motion.div>
                )}
            </nav>

            {/* User Section */}
            <div className="border-t border-white/5 p-4 bg-ch-black/20">
                {!collapsed ? (
                    <div className="flex items-center gap-2">
                        <NavLink
                            to="/settings"
                            className="flex items-center gap-3 flex-1 min-w-0 group cursor-pointer"
                        >
                            <div className="w-10 h-10 bg-gradient-to-br from-ch-dark-gray to-ch-black border border-white/5 group-hover:border-ch-orange/50 rounded-xl flex items-center justify-center text-ch-orange font-bold text-sm shadow-xl transition-all duration-300">
                                {user?.first_name?.[0]?.toUpperCase() || user?.email?.[0]?.toUpperCase() || 'U'}
                            </div>
                            <div className="flex-1 min-w-0">
                                <p className="text-sm font-bold text-ch-white truncate leading-tight group-hover:text-ch-orange transition-colors">
                                    {user?.first_name || 'Usuário'}
                                </p>
                                <p className="text-[10px] text-ch-text-dimmed truncate uppercase tracking-wider">
                                    {user?.company?.name || 'Sem empresa'}
                                </p>
                            </div>
                        </NavLink>
                        <button
                            onClick={signOut}
                            className="p-2.5 text-ch-text-dimmed hover:text-rose-500 hover:bg-white/5 rounded-xl transition-all duration-300"
                            title="Sair"
                        >
                            <LogOut className="w-4 h-4" />
                        </button>
                    </div>
                ) : (
                    <button
                        onClick={signOut}
                        className="w-full h-11 text-ch-text-dimmed hover:text-ch-orange hover:bg-white/5 rounded-xl transition-all duration-300 flex items-center justify-center shadow-inner"
                        title="Sair"
                    >
                        <LogOut className="w-5 h-5" />
                    </button>
                )}
            </div>
        </aside >
    );
}

import { useState, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Form, FormControl, FormDescription, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';
import { Loader2, User } from 'lucide-react';

const profileSchema = z.object({
    first_name: z.string().min(2, 'Nome deve ter pelo menos 2 caracteres'),
    last_name: z.string().min(2, 'Sobrenome deve ter pelo menos 2 caracteres'),
    email: z.string().email('Email inválido').optional(), // Read-only mostly
});

type ProfileFormValues = z.infer<typeof profileSchema>;

export function ProfileForm() {
    const { user, refreshUser } = useAuth();
    const [isLoading, setIsLoading] = useState(false);

    const form = useForm<ProfileFormValues>({
        resolver: zodResolver(profileSchema),
        defaultValues: {
            first_name: '',
            last_name: '',
            email: '',
        },
    });

    useEffect(() => {
        if (user) {
            form.reset({
                first_name: user.first_name || '',
                last_name: user.last_name || '',
                email: user.email || '',
            });
        }
    }, [user, form]);

    const onSubmit = async (data: ProfileFormValues) => {
        if (!user) return;
        setIsLoading(true);
        try {
            const { error } = await supabase
                .from('users')
                .update({
                    first_name: data.first_name,
                    last_name: data.last_name,
                })
                .eq('id', user.id);

            if (error) throw error;

            await refreshUser();
            toast.success('Perfil atualizado com sucesso!');
        } catch (error) {
            console.error('Error updating profile:', error);
            toast.error('Erro ao atualizar perfil.');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="space-y-6">
            <div>
                <h3 className="text-lg font-medium text-ch-white">Informações Pessoais</h3>
                <p className="text-sm text-ch-text-muted">Atualize suas informações de identificação.</p>
            </div>
            <div className="p-6 glass-card border-white/5 rounded-2xl">
                <Form {...form}>
                    <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <FormField
                                control={form.control}
                                name="first_name"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel className="text-ch-text-dimmed">Nome</FormLabel>
                                        <FormControl>
                                            <div className="relative">
                                                <User className="absolute left-3 top-2.5 h-4 w-4 text-ch-text-muted" />
                                                <Input placeholder="Seu nome" className="pl-9 bg-white/5 border-white/10 text-ch-white" {...field} />
                                            </div>
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />
                            <FormField
                                control={form.control}
                                name="last_name"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel className="text-ch-text-dimmed">Sobrenome</FormLabel>
                                        <FormControl>
                                            <Input placeholder="Seu sobrenome" className="bg-white/5 border-white/10 text-ch-white" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />
                        </div>

                        <FormField
                            control={form.control}
                            name="email"
                            render={({ field }) => (
                                <FormItem>
                                    <FormLabel className="text-ch-text-dimmed">Email</FormLabel>
                                    <FormControl>
                                        <Input placeholder="seu@email.com" className="bg-white/5 border-white/10 text-ch-text-muted cursor-not-allowed" {...field} disabled />
                                    </FormControl>
                                    <FormDescription className="text-xs text-white/30">
                                        O email não pode ser alterado diretamente por questões de segurança.
                                    </FormDescription>
                                    <FormMessage />
                                </FormItem>
                            )}
                        />

                        <div className="flex justify-end">
                            <Button type="submit" disabled={isLoading} className="bg-ch-orange text-black hover:bg-ch-orange/90">
                                {isLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                                Salvar Alterações
                            </Button>
                        </div>
                    </form>
                </Form>
            </div>
        </div>
    );
}

import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';
import { Loader2, Lock } from 'lucide-react';

const securitySchema = z.object({
    password: z.string().min(6, 'A senha deve ter pelo menos 6 caracteres'),
    confirmPassword: z.string().min(6, 'A confirmação deve ter pelo menos 6 caracteres'),
}).refine((data) => data.password === data.confirmPassword, {
    message: "As senhas não conferem",
    path: ["confirmPassword"],
});

type SecurityFormValues = z.infer<typeof securitySchema>;

export function SecurityForm() {
    const [isLoading, setIsLoading] = useState(false);

    const form = useForm<SecurityFormValues>({
        resolver: zodResolver(securitySchema),
        defaultValues: {
            password: '',
            confirmPassword: '',
        },
    });

    const onSubmit = async (data: SecurityFormValues) => {
        setIsLoading(true);
        try {
            const { error } = await supabase.auth.updateUser({
                password: data.password
            });

            if (error) throw error;

            toast.success('Senha atualizada com sucesso!');
            form.reset();
        } catch (error) {
            console.error('Error updating password:', error);
            toast.error('Erro ao atualizar senha. Tente novamente.');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="space-y-6">
            <div>
                <h3 className="text-lg font-medium text-ch-white">Segurança</h3>
                <p className="text-sm text-ch-text-muted">Gerencie sua senha e acesso.</p>
            </div>
            <div className="p-6 glass-card border-white/5 rounded-2xl">
                <Form {...form}>
                    <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4 max-w-md">
                        <FormField
                            control={form.control}
                            name="password"
                            render={({ field }) => (
                                <FormItem>
                                    <FormLabel className="text-ch-text-dimmed">Nova Senha</FormLabel>
                                    <FormControl>
                                        <div className="relative">
                                            <Lock className="absolute left-3 top-2.5 h-4 w-4 text-ch-text-muted" />
                                            <Input type="password" placeholder="••••••••" className="pl-9 bg-white/5 border-white/10 text-ch-white" {...field} />
                                        </div>
                                    </FormControl>
                                    <FormMessage />
                                </FormItem>
                            )}
                        />
                        <FormField
                            control={form.control}
                            name="confirmPassword"
                            render={({ field }) => (
                                <FormItem>
                                    <FormLabel className="text-ch-text-dimmed">Confirmar Nova Senha</FormLabel>
                                    <FormControl>
                                        <div className="relative">
                                            <Lock className="absolute left-3 top-2.5 h-4 w-4 text-ch-text-muted" />
                                            <Input type="password" placeholder="••••••••" className="pl-9 bg-white/5 border-white/10 text-ch-white" {...field} />
                                        </div>
                                    </FormControl>
                                    <FormMessage />
                                </FormItem>
                            )}
                        />

                        <div className="pt-2">
                            <Button type="submit" disabled={isLoading} className="bg-ch-orange text-black hover:bg-ch-orange/90 w-full sm:w-auto">
                                {isLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                                Atualizar Senha
                            </Button>
                        </div>
                    </form>
                </Form>
            </div>
        </div>
    );
}

import React from 'react';
import { Badge } from '@/components/ui/badge';
import { Tag } from '@/hooks/useTags';
import { X } from 'lucide-react';

interface TagBadgeProps {
    tag: Tag;
    onRemove?: () => void;
    className?: string;
}

export function TagBadge({ tag, onRemove, className }: TagBadgeProps) {
    return (
        <Badge
            variant="secondary"
            style={{
                backgroundColor: `${tag.color}20`,
                color: tag.color,
                borderColor: `${tag.color}40`
            }}
            className={`flex items-center gap-1 font-medium ${className}`}
        >
            {tag.name}
            {onRemove && (
                <button
                    onClick={(e) => {
                        e.stopPropagation();
                        onRemove();
                    }}
                    className="hover:bg-slate-200 rounded-full p-0.5"
                >
                    <X className="h-3 w-3" />
                </button>
            )}
        </Badge>
    );
}

export function TagList({ tags, onRemoveTag, className }: {
    tags?: { tag: Tag }[],
    onRemoveTag?: (tagId: string) => void,
    className?: string
}) {
    if (!tags || tags.length === 0) return null;

    return (
        <div className={`flex flex-wrap gap-2 ${className}`}>
            {tags.map(({ tag }) => (
                <TagBadge
                    key={tag.id}
                    tag={tag}
                    onRemove={onRemoveTag ? () => onRemoveTag(tag.id) : undefined}
                />
            ))}
        </div>
    );
}

import React, { useState } from 'react';
import { Check, Plus, Tag as TagIcon } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import {
    Command,
    CommandEmpty,
    CommandGroup,
    CommandInput,
    CommandItem,
    CommandList,
} from '@/components/ui/command';
import {
    Popover,
    PopoverContent,
    PopoverTrigger,
} from '@/components/ui/popover';
import { useTags, useTagMutations, Tag } from '@/hooks/useTags';
import { cn } from '@/lib/utils';

interface TagSelectorProps {
    entityId: string;
    entityType: 'campaign' | 'creative';
    selectedTags: { tag: Tag }[];
}

const COLORS = [
    '#6366f1', '#ec4899', '#f59e0b', '#10b981', '#3b82f6', '#ef4444', '#8b5cf6', '#f97316'
];

export function TagSelector({ entityId, entityType, selectedTags }: TagSelectorProps) {
    const [open, setOpen] = useState(false);
    const [searchValue, setSearchValue] = useState('');
    const { data: allTags = [] } = useTags(entityType);
    const { createTag, addTagToEntity, removeTagFromEntity } = useTagMutations();

    const selectedIds = new Set(selectedTags.map(t => t.tag.id));

    const handleSelect = (tag: Tag) => {
        if (selectedIds.has(tag.id)) {
            removeTagFromEntity.mutate({ tagId: tag.id, entityId, entityType });
        } else {
            addTagToEntity.mutate({ tagId: tag.id, entityId, entityType });
        }
    };

    const handleCreateTag = () => {
        if (!searchValue) return;

        const randomColor = COLORS[Math.floor(Math.random() * COLORS.length)];
        createTag.mutate({
            name: searchValue,
            color: randomColor,
            entity_type: entityType
        }, {
            onSuccess: (newTag) => {
                addTagToEntity.mutate({ tagId: newTag.id, entityId, entityType });
                setSearchValue('');
            }
        });
    };

    return (
        <Popover open={open} onOpenChange={setOpen}>
            <PopoverTrigger asChild>
                <Button variant="ghost" size="sm" className="h-8 w-8 p-0 hover:bg-slate-100">
                    <Plus className="h-4 w-4" />
                </Button>
            </PopoverTrigger>
            <PopoverContent className="w-[200px] p-0" align="start">
                <Command>
                    <CommandInput
                        placeholder="Buscar ou criar tag..."
                        value={searchValue}
                        onValueChange={setSearchValue}
                    />
                    <CommandList>
                        <CommandEmpty>
                            <Button
                                variant="ghost"
                                className="w-full justify-start text-xs h-8"
                                onClick={handleCreateTag}
                                disabled={createTag.isPending}
